interface MenuItem {
  href: string
  label: string
  icon: React.ComponentType<{ className?: string }>
}

interface MenuSection {
  title: string
  items: MenuItem[]
}

export default function Sidebar() {
  const pathname = usePathname()
  const searchParams = useSearchParams()
  const [savedContext, setSavedContext] = useState<string | null>(null)

  // from 파라미터로 현재 섹션 추적
  const fromParam = searchParams.get('from')
  const fromQC = fromParam === 'qc'
  const fromCX = fromParam === 'cx'

  // 현재 섹션 컨텍스트 저장 및 복원 (클라이언트 전용)
  useEffect(() => {
    const isQCPage = pathname.startsWith('/cost') || pathname.startsWith('/sets') || pathname.startsWith('/materials') || pathname.startsWith('/qc') || pathname.startsWith('/admin') || pathname.startsWith('/sales')
    const isCXPage = pathname.startsWith('/cx')
    const isB2BPage = pathname.startsWith('/b2b')

    // QC/CX 페이지에 있을 때 컨텍스트 저장
    if (isQCPage && !isB2BPage) {
      sessionStorage.setItem('sidebarContext', 'qc')
      setSavedContext('qc')
    } else if (isCXPage && !isB2BPage) {
      sessionStorage.setItem('sidebarContext', 'cx')
      setSavedContext('cx')
    }
    // B2B 페이지가 아닌 다른 페이지는 컨텍스트 초기화
    else if (!isB2BPage && !pathname.startsWith('/sku') && pathname !== '/') {
      sessionStorage.removeItem('sidebarContext')
      setSavedContext(null)
    }
    // B2B 페이지에서는 저장된 컨텍스트 불러오기
    else if (isB2BPage) {
      const context = sessionStorage.getItem('sidebarContext')
      setSavedContext(context)
    }
  }, [pathname])

  const allMenuSections: MenuSection[] = [
    {
      title: 'QC',
      items: [
        { href: '/qc/dashboard', label: 'QC 대시보드', icon: DashboardIcon },
        { href: '/cost', label: '판매가 관리', icon: CurrencyIcon },
        { href: '/sets', label: '세트 가격', icon: BagIcon },
        { href: '/materials', label: '단가 마스터', icon: CubeIcon },
        { href: '/sku?from=qc', label: '상품번호(SKU)', icon: TagIcon },
        { href: '/qc/inventory', label: '재고 현황', icon: CubeIcon },
        { href: '/qc/shipment', label: '3PL 출고관리', icon: TruckIcon },
        { href: '/qc/manufacturer', label: '제조사 출고관리', icon: FactoryIcon },
      ]
    },
    {
      title: '판매현황',
      items: [
        { href: '/sales/orders', label: '출고 데이터 업로드', icon: TruckIcon },
        { href: '/sales/dashboard', label: '판매량 대시보드', icon: DashboardIcon },
        { href: '/sales/product-daily', label: '제품별 일별 현황', icon: BookIcon },
      ]
    },
    {
      title: '관리자',
      items: [
        { href: '/admin/cost', label: '원가 입력', icon: ShieldIcon },
        { href: '/admin/b2b-mapping', label: 'B2B 매핑 관리', icon: RefreshIcon },
        { href: '/admin/data-viewer', label: '데이터 뷰어', icon: DatabaseIcon },
      ]
    },
    {
      title: 'CX',
      items: [
        { href: '/cx/guide', label: 'CS 가이드', icon: BookIcon },
        { href: '/cx/returns', label: '반품/교환', icon: RefreshIcon },
        { href: '/sku?from=cx', label: '상품번호(SKU)', icon: TagIcon },
        { href: '/cx/order-automation', label: '발주 자동화', icon: ShoppingCartIcon },
      ]
    },
    {
      title: 'B2B',
      items: [
        { href: '/b2b/pricing', label: '단가표', icon: CurrencyIcon },
        { href: '/b2b/guide', label: 'B2B 가이드', icon: BookIcon },
        { href: '/b2b/companies', label: '진행업체', icon: UsersIcon },
        { href: '/b2b/outbound', label: '아웃바운딩', icon: ShoppingCartIcon },
      ]
    },
    {
      title: '물류',
      items: [
        { href: 'https://www.barun21.net/', label: '바른로지스틱스', icon: TruckIcon },
      ]
    },
    {
      title: '아임웹',
      items: [
        { href: '/imweb', label: '상품 목록', icon: CubeIcon },
        { href: '/imweb/orders', label: '주문 목록', icon: ShoppingCartIcon },
      ]
    }
  ]

  // 현재 페이지에 맞는 섹션만 필터링
  const isSKUPage = pathname.startsWith('/sku')
  const isQCPage = pathname.startsWith('/cost') || pathname.startsWith('/sets') || pathname.startsWith('/materials') || pathname.startsWith('/qc')
  const isCXPage = pathname.startsWith('/cx')
  const isB2BPage = pathname.startsWith('/b2b')
  const isImwebPage = pathname.startsWith('/imweb')
  const isAdminPage = pathname.startsWith('/admin')
  const isSalesPage = pathname.startsWith('/sales')

  let menuSections = allMenuSections

  // from 파라미터가 있으면 우선 적용 (섹션 간 이동 시 사이드바 유지)
  if (fromCX) {
    // CX에서 진입한 경우: 항상 CX + B2B + 물류 유지
    menuSections = allMenuSections.filter(section => section.title === 'CX' || section.title === 'B2B' || section.title === '물류')
  } else if (fromQC) {
    // QC에서 진입한 경우: 항상 QC + B2B + 관리자 + 판매현황 + 물류 유지
    menuSections = allMenuSections.filter(section => section.title === 'QC' || section.title === 'B2B' || section.title === '관리자' || section.title === '판매현황' || section.title === '물류')
  } else if (isQCPage) {
    // QC 페이지: QC + B2B + 관리자 + 판매현황 + 물류
    menuSections = allMenuSections.filter(section => section.title === 'QC' || section.title === 'B2B' || section.title === '관리자' || section.title === '판매현황' || section.title === '물류')
  } else if (isCXPage) {
    // CX 페이지: CX + B2B + 물류
    menuSections = allMenuSections.filter(section => section.title === 'CX' || section.title === 'B2B' || section.title === '물류')
  } else if (isB2BPage) {
    // B2B 페이지: 이전 섹션 컨텍스트 유지
    if (savedContext === 'qc') {
      // QC에서 진입한 경우: QC + B2B + 관리자 + 판매현황 + 물류
      menuSections = allMenuSections.filter(section => section.title === 'QC' || section.title === 'B2B' || section.title === '관리자' || section.title === '판매현황' || section.title === '물류')
    } else if (savedContext === 'cx') {
      // CX에서 진입한 경우: CX + B2B + 물류
      menuSections = allMenuSections.filter(section => section.title === 'CX' || section.title === 'B2B' || section.title === '물류')
    } else {
      // 직접 접근한 경우 또는 컨텍스트 로딩 중: B2B + 물류만 표시
      menuSections = allMenuSections.filter(section => section.title === 'B2B' || section.title === '물류')
    }
  } else if (isImwebPage) {
    menuSections = allMenuSections.filter(section => section.title === '아임웹' || section.title === '물류')
  } else if (isAdminPage) {
    menuSections = allMenuSections.filter(section => section.title === '관리자' || section.title === 'QC' || section.title === 'B2B' || section.title === '판매현황' || section.title === '물류')
  } else if (isSalesPage) {
    menuSections = allMenuSections.filter(section => section.title === '판매현황' || section.title === 'QC' || section.title === 'B2B' || section.title === '관리자' || section.title === '물류')
  }

  return (
    <aside className="w-64 bg-gray-900 h-screen flex flex-col sticky top-0 overflow-y-auto">
      <div className="p-6 border-b border-gray-800">
        <Link href="/" className="flex items-center gap-3">
          <div className="w-8 h-8 bg-green-500 rounded-lg flex items-center justify-center">
            <span className="text-white font-bold text-lg">L</span>
          </div>
          <h1 className="text-xl font-bold text-white tracking-tight">likethix</h1>
        </Link>
      </div>

      <nav className="flex-1 p-4 space-y-6" suppressHydrationWarning>
        {/* 홈 */}
        <Link
          href="/"
          className={`flex items-center gap-3 px-4 py-3 rounded-lg transition-all ${
            pathname === '/'
              ? 'bg-gray-800 text-white'
              : 'text-gray-400 hover:bg-gray-800/50 hover:text-white'
          }`}
        >
          <HomeIcon className="w-5 h-5" />
          <span className="text-sm font-medium">홈</span>
        </Link>

        {/* 섹션별 메뉴 */}
        {menuSections.map((section) => (
          <div key={section.title}>
            <h3 className="px-4 mb-2 text-xs font-semibold text-gray-500 uppercase tracking-wider">
              {section.title}
            </h3>
            <div className="space-y-1">
              {section.items.map((item) => {
                const isActive = pathname === item.href
                const Icon = item.icon
                const isExternalLink = item.href.startsWith('http')

                // 외부 링크는 <a> 태그 사용
                if (isExternalLink) {
                  return (
                    <a
                      key={item.href}
                      href={item.href}
                      target="_blank"
                      rel="noopener noreferrer"
                      className="flex items-center gap-3 px-4 py-3 rounded-lg transition-all text-gray-400 hover:bg-gray-800/50 hover:text-white"
                    >
                      <Icon className="w-5 h-5" />
                      <span className="text-sm font-medium">{item.label}</span>
                      <svg className="w-3 h-3 ml-auto" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M10 6H6a2 2 0 00-2 2v10a2 2 0 002 2h10a2 2 0 002-2v-4M14 4h6m0 0v6m0-6L10 14" />
                      </svg>
                    </a>
                  )
                }

                return (
                  <Link
                    key={item.href}
                    href={item.href}
                    className={`flex items-center gap-3 px-4 py-3 rounded-lg transition-all ${
                      isActive
                        ? 'bg-gray-800 text-white'
                        : 'text-gray-400 hover:bg-gray-800/50 hover:text-white'
                    }`}
                  >
                    <Icon className="w-5 h-5" />
                    <span className="text-sm font-medium">{item.label}</span>
                  </Link>
                )
              })}
            </div>
          </div>
        ))}
      </nav>

      <div className="p-4 border-t border-gray-800">
        <div className="px-4 py-3 bg-gray-800/50 rounded-lg">
          <p className="text-xs text-gray-400">QC 데이터 관리</p>
          <p className="text-sm text-white font-medium mt-1">v1.0.0</p>
        </div>
      </div>
    </aside>
  )
}

