'use client'

import { useState } from 'react'

interface Props {
  monthlyData: Record<string, Record<number, number>>
  weeklyData: Record<string, Record<number, number>>
  totalByGroup: Record<string, number>
}

const PRODUCT_GROUPS = ['미니멀러그', '그레인러그', '시어서커', '사이잘러그']
const GROUP_COLORS: Record<string, { bg: string; text: string; border: string }> = {
  '미니멀러그': { bg: '#EEF2FF', text: '#4F46E5', border: '#C7D2FE' },
  '그레인러그': { bg: '#FEF3C7', text: '#D97706', border: '#FDE68A' },
  '시어서커': { bg: '#DBEAFE', text: '#2563EB', border: '#BFDBFE' },
  '사이잘러그': { bg: '#D1FAE5', text: '#059669', border: '#A7F3D0' },
}

export default function ClientPage({ monthlyData, weeklyData, totalByGroup }: Props) {
  const [viewType, setViewType] = useState<'monthly' | 'weekly'>('monthly')

  // 전체 합계
  const grandTotal = Object.values(totalByGroup).reduce((sum, v) => sum + v, 0)

  // 월별 데이터 (1~12월)
  const months = Array.from({ length: 12 }, (_, i) => i + 1)

  // 주차 데이터 (전체 주차 찾기)
  const allWeeks = new Set<number>()
  Object.values(weeklyData).forEach(weekMap => {
    Object.keys(weekMap).forEach(week => allWeeks.add(parseInt(week)))
  })
  const weeks = Array.from(allWeeks).sort((a, b) => a - b)

  return (
    <div className="space-y-6">
      {/* 제품군별 요약 카드 */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
        {PRODUCT_GROUPS.map(group => {
          const total = totalByGroup[group] || 0
          const ratio = grandTotal > 0 ? (total / grandTotal * 100) : 0
          const colors = GROUP_COLORS[group]

          return (
            <div
              key={group}
              className="rounded-xl p-6 border-2 shadow-sm hover:shadow-md transition-shadow"
              style={{
                background: colors.bg,
                borderColor: colors.border,
              }}
            >
              <h3 className="text-sm font-semibold mb-2" style={{ color: colors.text }}>
                {group}
              </h3>
              <div className="flex items-baseline gap-2 mb-1">
                <span className="text-3xl font-bold" style={{ color: colors.text }}>
                  {total.toLocaleString()}
                </span>
                <span className="text-sm" style={{ color: colors.text, opacity: 0.7 }}>
                  개
                </span>
              </div>
              <div className="flex items-center gap-2 mt-2">
                <div className="flex-1 h-2 bg-white/50 rounded-full overflow-hidden">
                  <div
                    className="h-full rounded-full transition-all"
                    style={{
                      width: `${ratio}%`,
                      background: colors.text,
                    }}
                  />
                </div>
                <span className="text-xs font-medium" style={{ color: colors.text }}>
                  {ratio.toFixed(1)}%
                </span>
              </div>
            </div>
          )
        })}
      </div>

      {/* 전체 합계 */}
      <div className="bg-white rounded-xl p-6 shadow-sm border border-gray-200">
        <div className="flex items-center justify-between">
          <h3 className="text-lg font-semibold text-gray-900">2026년 전체 판매량</h3>
          <div className="flex items-baseline gap-2">
            <span className="text-3xl font-bold text-gray-900">
              {grandTotal.toLocaleString()}
            </span>
            <span className="text-sm text-gray-500">개</span>
          </div>
        </div>
      </div>

      {/* 보기 방식 선택 */}
      <div className="flex items-center gap-3">
        <button
          onClick={() => setViewType('monthly')}
          className={`px-4 py-2 rounded-lg font-medium transition-all ${
            viewType === 'monthly'
              ? 'bg-blue-600 text-white shadow-sm'
              : 'bg-white text-gray-600 border border-gray-300 hover:bg-gray-50'
          }`}
        >
          월별 보기
        </button>
        <button
          onClick={() => setViewType('weekly')}
          className={`px-4 py-2 rounded-lg font-medium transition-all ${
            viewType === 'weekly'
              ? 'bg-blue-600 text-white shadow-sm'
              : 'bg-white text-gray-600 border border-gray-300 hover:bg-gray-50'
          }`}
        >
          주간별 보기
        </button>
      </div>

      {/* 월별 테이블 */}
      {viewType === 'monthly' && (
        <div className="bg-white rounded-xl shadow-sm border border-gray-200 overflow-hidden">
          <div className="overflow-x-auto">
            <table className="w-full">
              <thead>
                <tr className="bg-gray-50 border-b border-gray-200">
                  <th className="px-6 py-4 text-left text-xs font-semibold text-gray-600 uppercase tracking-wider sticky left-0 bg-gray-50">
                    제품군
                  </th>
                  {months.map(month => (
                    <th
                      key={month}
                      className="px-4 py-4 text-center text-xs font-semibold text-gray-600 uppercase tracking-wider"
                    >
                      {month}월
                    </th>
                  ))}
                  <th className="px-6 py-4 text-right text-xs font-semibold text-gray-600 uppercase tracking-wider">
                    합계
                  </th>
                </tr>
              </thead>
              <tbody className="divide-y divide-gray-200">
                {PRODUCT_GROUPS.map(group => {
                  const monthlyValues = months.map(month => monthlyData[group]?.[month] || 0)
                  const rowTotal = monthlyValues.reduce((sum, v) => sum + v, 0)
                  const colors = GROUP_COLORS[group]

                  return (
                    <tr key={group} className="hover:bg-gray-50 transition-colors">
                      <td
                        className="px-6 py-4 font-semibold sticky left-0 bg-white"
                        style={{ color: colors.text }}
                      >
                        {group}
                      </td>
                      {monthlyValues.map((value, idx) => (
                        <td key={months[idx]} className="px-4 py-4 text-center text-sm text-gray-900">
                          {value > 0 ? value.toLocaleString() : '-'}
                        </td>
                      ))}
                      <td className="px-6 py-4 text-right font-semibold text-gray-900">
                        {rowTotal.toLocaleString()}
                      </td>
                    </tr>
                  )
                })}
                {/* 총합계 행 */}
                <tr className="bg-gray-100 font-semibold">
                  <td className="px-6 py-4 sticky left-0 bg-gray-100">월별 합계</td>
                  {months.map(month => {
                    const monthTotal = PRODUCT_GROUPS.reduce(
                      (sum, g) => sum + (monthlyData[g]?.[month] || 0),
                      0
                    )
                    return (
                      <td key={month} className="px-4 py-4 text-center text-gray-900">
                        {monthTotal.toLocaleString()}
                      </td>
                    )
                  })}
                  <td className="px-6 py-4 text-right text-gray-900">
                    {grandTotal.toLocaleString()}
                  </td>
                </tr>
              </tbody>
            </table>
          </div>
        </div>
      )}

      {/* 주간별 테이블 */}
      {viewType === 'weekly' && (
        <div className="bg-white rounded-xl shadow-sm border border-gray-200 overflow-hidden">
          <div className="overflow-x-auto">
            <table className="w-full">
              <thead>
                <tr className="bg-gray-50 border-b border-gray-200">
                  <th className="px-6 py-4 text-left text-xs font-semibold text-gray-600 uppercase tracking-wider sticky left-0 bg-gray-50">
                    제품군
                  </th>
                  {weeks.map(week => (
                    <th
                      key={week}
                      className="px-3 py-4 text-center text-xs font-semibold text-gray-600 uppercase tracking-wider"
                    >
                      W{week.toString().padStart(2, '0')}
                    </th>
                  ))}
                  <th className="px-6 py-4 text-right text-xs font-semibold text-gray-600 uppercase tracking-wider">
                    합계
                  </th>
                </tr>
              </thead>
              <tbody className="divide-y divide-gray-200">
                {PRODUCT_GROUPS.map(group => {
                  const weeklyValues = weeks.map(week => weeklyData[group]?.[week] || 0)
                  const rowTotal = weeklyValues.reduce((sum, v) => sum + v, 0)
                  const colors = GROUP_COLORS[group]

                  return (
                    <tr key={group} className="hover:bg-gray-50 transition-colors">
                      <td
                        className="px-6 py-4 font-semibold sticky left-0 bg-white"
                        style={{ color: colors.text }}
                      >
                        {group}
                      </td>
                      {weeklyValues.map((value, idx) => (
                        <td key={weeks[idx]} className="px-3 py-4 text-center text-sm text-gray-900">
                          {value > 0 ? Math.round(value).toLocaleString() : '-'}
                        </td>
                      ))}
                      <td className="px-6 py-4 text-right font-semibold text-gray-900">
                        {rowTotal.toLocaleString()}
                      </td>
                    </tr>
                  )
                })}
                {/* 총합계 행 */}
                <tr className="bg-gray-100 font-semibold">
                  <td className="px-6 py-4 sticky left-0 bg-gray-100">주간 합계</td>
                  {weeks.map(week => {
                    const weekTotal = PRODUCT_GROUPS.reduce(
                      (sum, g) => sum + (weeklyData[g]?.[week] || 0),
                      0
                    )
                    return (
                      <td key={week} className="px-3 py-4 text-center text-gray-900">
                        {Math.round(weekTotal).toLocaleString()}
                      </td>
                    )
                  })}
                  <td className="px-6 py-4 text-right text-gray-900">
                    {grandTotal.toLocaleString()}
                  </td>
                </tr>
              </tbody>
            </table>
          </div>
        </div>
      )}

      {/* 월별 비중 차트 */}
      <div className="bg-white rounded-xl p-6 shadow-sm border border-gray-200">
        <h3 className="text-lg font-semibold text-gray-900 mb-4">월별 제품군 비중 (%)</h3>
        <div className="overflow-x-auto">
          <table className="w-full">
            <thead>
              <tr className="border-b border-gray-200">
                <th className="px-4 py-3 text-left text-sm font-semibold text-gray-600">제품군</th>
                {months.map(month => (
                  <th key={month} className="px-4 py-3 text-center text-sm font-semibold text-gray-600">
                    {month}월
                  </th>
                ))}
              </tr>
            </thead>
            <tbody className="divide-y divide-gray-200">
              {PRODUCT_GROUPS.map(group => {
                const colors = GROUP_COLORS[group]
                return (
                  <tr key={group} className="hover:bg-gray-50">
                    <td className="px-4 py-3 font-semibold" style={{ color: colors.text }}>
                      {group}
                    </td>
                    {months.map(month => {
                      const monthTotal = PRODUCT_GROUPS.reduce(
                        (sum, g) => sum + (monthlyData[g]?.[month] || 0),
                        0
                      )
                      const groupValue = monthlyData[group]?.[month] || 0
                      const ratio = monthTotal > 0 ? (groupValue / monthTotal * 100) : 0
                      return (
                        <td key={month} className="px-4 py-3 text-center">
                          <span className="text-sm font-medium text-gray-900">
                            {ratio > 0 ? ratio.toFixed(1) + '%' : '-'}
                          </span>
                        </td>
                      )
                    })}
                  </tr>
                )
              })}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  )
}

