  return weekNum
}

export default async function ProductGroupsPage() {
  console.log('🔍 제품군별 분석 페이지 데이터 로딩 시작')

  // 1. product_barcodes에서 제품군별 바코드 조회
  const productGroups = {
    '미니멀러그': { search: '%미니멀러그%', barcodes: [] as string[] },
    '그레인러그': { search: '그레인%', barcodes: [] as string[] },
    '시어서커': { search: '%시어서커%', barcodes: [] as string[] },
    '사이잘러그': { search: '%사이잘%', barcodes: [] as string[] },
    '방석/쿠션': { search: '%방석%', barcodes: [] as string[] },
    '블랭킷': { search: '%블랭킷%', barcodes: [] as string[] },
  }

  const barcodeToGroup: Record<string, string> = {}

  for (const [groupName, groupData] of Object.entries(productGroups)) {
    const { data } = await supabase
      .from('product_barcodes')
      .select('barcode, product_name')
      .ilike('product_name', groupData.search)

    if (data) {
      for (const item of data) {
        // 충전재/내장재/포장재 제외
        if (['충전재', '내장재', '포장재', '박스', '비닐'].some(x => item.product_name?.includes(x))) {
          continue
        }
        groupData.barcodes.push(item.barcode)
        barcodeToGroup[item.barcode] = groupName
      }
    }

    console.log(`  ${groupName}: ${groupData.barcodes.length}개 제품`)
  }

  // 2. daily_sales에서 2026년 데이터 조회 (모든 바코드)
  const allBarcodes = Object.values(productGroups).flatMap(g => g.barcodes)
  const salesData: any[] = []

  // 배치 처리
  const batchSize = 100
  for (let i = 0; i < allBarcodes.length; i += batchSize) {
    const batch = allBarcodes.slice(i, i + batchSize)
    const { data } = await supabase
      .from('daily_sales')
      .select('*')
      .in('product_barcode', batch)
      .gte('sale_date', '2026-01-01')
      .lte('sale_date', '2026-12-31')

    if (data) {
      salesData.push(...data)
    }
  }

  console.log(`  조회된 판매 레코드: ${salesData.length}개`)

  // 3. 제품군별 월별/주간별 집계
  const monthlyData: Record<string, Record<number, number>> = {}
  const weeklyData: Record<string, Record<number, number>> = {}
  const totalByGroup: Record<string, number> = {}

  Object.keys(productGroups).forEach(group => {
    monthlyData[group] = {}
    weeklyData[group] = {}
    totalByGroup[group] = 0
  })

  salesData.forEach(record => {
    const barcode = record.product_barcode
    const group = barcodeToGroup[barcode]
    if (!group) return

    const saleDate = record.sale_date
    const quantity = parseFloat(record.quantity) || 0
    const month = parseInt(saleDate.split('-')[1])
    const week = getWeekNumber(saleDate)

    monthlyData[group][month] = (monthlyData[group][month] || 0) + quantity
    weeklyData[group][week] = (weeklyData[group][week] || 0) + quantity
    totalByGroup[group] = (totalByGroup[group] || 0) + quantity
  })

  console.log('✅ 데이터 집계 완료')

  return (
    <main className="min-h-screen" style={{ background: '#F6F6F2' }}>
      <div className="max-w-full mx-auto px-8 py-10">
        {/* 페이지 헤더 */}
        <div className="mb-8">
          <h1 className="text-3xl font-bold tracking-tight mb-2" style={{ color: '#212121' }}>
            📊 제품군별 판매 분석
          </h1>
          <p className="text-sm" style={{ color: '#999999' }}>
            미니멀러그, 그레인러그, 시어서커, 사이잘러그 판매량 추이
          </p>
        </div>

        {/* 클라이언트 페이지 */}
        <ClientPage
          monthlyData={monthlyData}
          weeklyData={weeklyData}
          totalByGroup={totalByGroup}
        />
      </div>
    </main>
  )
}

