'use client'

import { useState, useEffect } from 'react'
import { supabase } from '@/lib/supabase'

interface ProductSKU {
  barcode: string
  sku_name: string
  product_category: string
  selling_price: number | null
}

interface Props {
  isOpen: boolean
  onClose: () => void
  productName: string
  currentBarcode?: string | null
  onSelect: (barcode: string, sellingPrice: number) => void
  onSelectMultiple?: (selections: Array<{ barcode: string; sellingPrice: number; size: string }>) => void
}

export default function BarcodeSelectModal({ isOpen, onClose, productName, currentBarcode, onSelect, onSelectMultiple }: Props) {
  const [loading, setLoading] = useState(false)
  const [skuList, setSkuList] = useState<ProductSKU[]>([])
  const [searchQuery, setSearchQuery] = useState('')
  const [selectedBarcodes, setSelectedBarcodes] = useState<Set<string>>(new Set())
  const [selectedCategory, setSelectedCategory] = useState<string>('전체')

  useEffect(() => {
    if (isOpen) {
      setSkuList([]) // 모달 열릴 때마다 초기화
      setSelectedBarcodes(new Set())
      setSelectedCategory('전체')
      fetchSKUs()
    }
  }, [isOpen])

  const fetchSKUs = async () => {
    setLoading(true)
    try {
      // 모든 단품 SKU 가져오기 (세트 제외)
      const { data, error } = await supabase
        .from('product_sku')
        .select('barcode, sku_name, product_category, selling_price, is_set')
        .eq('is_set', false) // 세트 제외, 단품만
        .order('product_category', { ascending: true })
        .order('sku_name', { ascending: true })

      if (error) throw error

      console.log(`전체 SKU 개수: ${data?.length || 0}`)

      setSkuList((data as ProductSKU[]) || [])
    } catch (error) {
      console.error('Error fetching SKUs:', error)
    } finally {
      setLoading(false)
    }
  }

  const toggleBarcode = (barcode: string) => {
    const newSelected = new Set(selectedBarcodes)
    if (newSelected.has(barcode)) {
      newSelected.delete(barcode)
    } else {
      newSelected.add(barcode)
    }
    setSelectedBarcodes(newSelected)
  }

  const handleApply = () => {
    if (selectedBarcodes.size === 0) {
      alert('최소 1개 이상 선택해주세요.')
      return
    }

    // 바코드 적용
    if (selectedBarcodes.size === 1 || !onSelectMultiple) {
      // 단일 선택
      const barcode = Array.from(selectedBarcodes)[0]
      const sku = skuList.find(s => s.barcode === barcode)
      if (sku) {
        onSelect(sku.barcode, sku.selling_price || 0)
      }
    } else {
      // 복수 선택
      const selections = Array.from(selectedBarcodes).map(barcode => {
        const sku = skuList.find(s => s.barcode === barcode)!
        const parsed = parseSKUName(sku.sku_name, sku.barcode)
        return {
          barcode: sku.barcode,
          sellingPrice: sku.selling_price || 0,
          size: parsed.size
        }
      })
      onSelectMultiple(selections)
    }

    // 모달 닫기
    setSelectedBarcodes(new Set())

