// mm → cm 변환
const convertToCm = (sizeStr: string): string => {
  return sizeStr.replace(/(\d+)/g, (match) => {
    const num = parseInt(match)
    // 350 이상이면 mm 단위로 판단 → cm로 변환 (10으로 나누기)
    // 350 미만이면 이미 cm 단위로 판단 → 변환하지 않음
    return num >= 350 ? (num / 10).toString() : match
  })
}

// 사이잘룩러그 v1 사이즈 매핑 (바코드 끝 3자리 기준, V2와 동일)
const sisalV1SizeMap: Record<string, string> = {
  '001': '45x65',
  '002': '65x200',
  '003': '100x150',
  '004': '150x200',
  '005': '200x250',
  '006': '200x300',
}

// SKU명 파싱 (괄호 안 _ 처리)
const parseSKUName = (skuName: string, barcode?: string) => {
  let product = ''
  let color = ''
  let sizePart = ''

  // 블랭킷 특별 처리: "티가든_블랭킷 / Milder_1000x1500(mm)" 또는 "티가든 블랭킷_Milder_Large_SET_1000x1500"
  if (skuName.includes('블랭킷')) {
    const blanketColors = ['Milder', 'Fresher', 'Happier']
    const foundColor = blanketColors.find(c => skuName.includes(c))
    if (foundColor) {
      product = '블랭킷'
      color = foundColor

      // 포장재 특별 처리: 152x368 → 포장재 Large, 112x368 → 포장재 Medium
      if (skuName.includes('포장재')) {
        if (skuName.includes('152x368')) {
          return { product, color, size: '포장재 Large', fullName: skuName }
        }
        if (skuName.includes('112x368')) {
          return { product, color, size: '포장재 Medium', fullName: skuName }
        }
        return { product, color, size: '포장재', fullName: skuName }
      }

      // 색상 이후의 사이즈 부분 추출
      const afterColor = skuName.split(foundColor)[1] || ''
      sizePart = afterColor.replace(/^[_\s/]+/, '').replace(/\(mm\)/g, '').trim()
      let sizeInCm = convertToCm(sizePart)
      return { product, color, size: sizeInCm, fullName: skuName }
    }
  }

  // 정규식: product_색상(영문)_사이즈 형식
  // 색상 부분의 (...) 안에는 _가 있어도 OK
  const match = skuName.match(/^(.+?)_([^_(]+\([^)]+\))_(.+)$/)

  if (match) {
    product = match[1]
    const colorPart = match[2]
    color = colorPart.substring(0, colorPart.indexOf('('))
    sizePart = match[3]
  } else {
    // 괄호 없는 경우: split으로 처리
    const parts = skuName.split('_')
    if (parts.length < 3) {
      return { product: '', color: '', size: skuName, fullName: skuName }
    }
    product = parts[0]
    color = parts[1]
    sizePart = parts.slice(2).join('_')
  }

  // 사이잘룩러그는 첫 번째 product만 사용 (시어서커_소파커버는 그대로)
  if (product.startsWith('사이잘룩러그')) {
    product = '사이잘룩러그'
  }

  let sizeInCm = convertToCm(sizePart)

  // 사이잘룩러그 "단품" v1 → 바코드로 사이즈 매핑 + v1 표시
  if (product === '사이잘룩러그' && sizeInCm === '단품' && barcode) {
    const sizeCode = barcode.slice(-3)
    const mappedSize = sisalV1SizeMap[sizeCode]
    if (mappedSize) {
      sizeInCm = `${mappedSize} V1`
    } else {
      sizeInCm = 'V1'
    }
  }

  return { product, color, size: sizeInCm, fullName: skuName }
}

